mapper.select:
/** 특정 수업의 출결 현황 */ SELECT a.* ,TRUNCATE((LATE_CNT+LEAVE_CNT)/3,0) ABSENT2_CNT ,b.login_id FROM ( SELECT tls.EDU_SEQ ,tls.USER_ID ,(SELECT USER_NM FROM t_user_info WHERE USER_ID=tls.USER_ID) USER_NM ,(SELECT EMAIL FROM t_user_info WHERE USER_ID=tls.USER_ID) EMAIL ,SUM(CASE WHEN tas.ATT_CD='O' THEN 1 ELSE 0 END) ATTEND_CNT ,SUM(CASE WHEN tas.ATT_CD='D' THEN 1 ELSE 0 END) LATE_CNT ,SUM(CASE WHEN tas.ATT_CD='Z' THEN 1 ELSE 0 END) LEAVE_CNT ,SUM(CASE WHEN tas.ATT_CD='X' THEN 1 ELSE 0 END) ABSENT_CNT ,COUNT(*) TIME_CNT FROM t_lecture_stdnt tls INNER JOIN t_lecture_time tlt ON tls.EDU_SEQ=tlt.EDU_SEQ LEFT OUTER JOIN t_attend_stdnt tas ON tlt.EDU_SEQ=tas.EDU_SEQ AND tlt.TIME_SEQ=tas.TIME_SEQ AND tls.USER_ID=tas.USER_ID WHERE tls.EDU_SEQ=#{eduSeq}
AND tls.USER_ID=#{userId}
GROUP BY tls.EDU_SEQ,tls.USER_ID ) a left join t_user_info b on a.user_id=b.user_id ORDER BY a.USER_NM

/** 학생의 출결 일별 리스트 */
select a.*
FROM t_attend_day_stdnt a  
WHERE 1=1 
and a.edu_seq =#{eduSeq}

ORDER BY a.edu_dt

select count(*) from ( select edu_seq from ( select tl.edu_seq , tls.user_id , count(*) time_cnt , sum(case when tas.att_cd = 'X' then 1 else 0 end) absent_cnt , sum(case when tas.att_cd = 'D' then 1 else 0 end) late_cnt , sum(case when tas.att_cd = 'Z' then 1 else 0 end) leave_cnt from t_lecture tl inner join t_lecture_time tlt on tl.edu_seq = tlt.edu_seq left join t_lecture_stdnt tls on tl.edu_seq = tls.edu_seq left join t_attend_stdnt tas on tl.edu_seq = tas.edu_seq and tlt.time_seq = tas.time_seq and tls.user_id = tas.user_id where 1=1
and tl.org_cd = #{reqOrgCd}
and tl.edu_nm like CONCAT('%',#{reqWrd},'%')
and tl.instctr_nm like CONCAT('%',#{reqWrd},'%')
and tl.edu_ctgry_seq = #{reqCtgry1}
and tl.detail_ctgry_seq = #{reqCtgry2}
group by tl.edu_seq ,tls.user_id ) a group by edu_seq ) a

SELECT a.* FROM (
select a.* ,1-((absent2_cnt+absent_cnt)/sum_time_cnt) att_ratio ,(select edu_nm from t_lecture where edu_seq=a.edu_seq) edu_nm ,(select instrctr_nm from t_lecture where edu_seq=a.edu_seq) prof_nm ,(select edu_ctgry_nm from t_lecture where edu_seq=a.edu_seq) edu_ctgry_nm ,(select edu_period_begin from t_lecture where edu_seq=a.edu_seq) edu_period_begin ,(select count(*) from t_lecture_stdnt where edu_seq=a.edu_seq) stdnt_cnt ,@rnum:=@rnum+1 AS R_NUM from ( select a.edu_seq ,sum(time_cnt) sum_time_cnt ,sum(truncate((late_cnt+leave_cnt)/3,0)) absent2_cnt ,sum(absent_cnt) absent_cnt ,(select count(*) from t_lecture_time tlt2 where tlt2.edu_seq=a.edu_seq) time_cnt from ( select tl.edu_seq , tls.user_id , count(*) time_cnt , sum(case when tas.att_cd = 'X' then 1 else 0 end) absent_cnt , sum(case when tas.att_cd = 'D' then 1 else 0 end) late_cnt , sum(case when tas.att_cd = 'Z' then 1 else 0 end) leave_cnt from t_lecture tl inner join t_lecture_time tlt on tl.edu_seq = tlt.edu_seq left join t_lecture_stdnt tls on tl.edu_seq = tls.edu_seq left join t_attend_stdnt tas on tl.edu_seq = tas.edu_seq and tlt.time_seq = tas.time_seq and tls.user_id = tas.user_id where 1=1
and tl.org_cd = #{reqOrgCd}
and tl.edu_nm like CONCAT('%',#{reqWrd},'%')
and tl.instctr_nm like CONCAT('%',#{reqWrd},'%')
and tl.edu_ctgry_seq = #{reqCtgry1}
and tl.detail_ctgry_seq = #{reqCtgry2}
group by tl.edu_seq ,tls.user_id ) a group by edu_seq ) a ,(SELECT @rnum:=0) B
) a LIMIT #{firstRecordIndex},#{recordCountPerPage}

/** 학생리스트 */ select a.* ,truncate((time_cnt-absent_cnt-truncate((leave_cnt+late_cnt)/3,0))/time_cnt*100,1) att_ratio ,(select user_nm from t_user_info tui where tui.user_id=a.user_id) stud_nm ,coalesce((select att_cd from t_attend_stdnt tas2 where tas2.user_id=a.user_id and edu_seq=#{eduSeq} and time_seq=#{timeSeq}),'W') att_cd ,#{timeSeq} time_seq from ( select tls.edu_seq,tls.user_id ,count(*) time_cnt ,sum(case when tas.att_cd = 'D' then 1 else 0 end) late_cnt ,sum(case when tas.att_cd = 'Z' then 1 else 0 end) leave_cnt ,sum(case when tas.att_cd = 'X' then 1 else 0 end) absent_cnt from t_lecture_stdnt tls inner join t_lecture_time tlt on tls.edu_seq =tlt.edu_seq left join t_attend_stdnt tas on tls.user_id =tas.user_id and tls.edu_seq =tas.edu_seq and tlt.time_seq =tas.time_seq where tls.edu_seq = #{eduSeq}
and tls.user_id=#{reqStudId}
group by tls.edu_seq,tls.user_id ) a

mapper.update:
/** 출결체크 완료 저장 */
update t_lecture_time
set check_status=1
where edu_seq=#{eduSeq} and time_seq=#{timeSeq}

/** 학생 인증여부 초기화 */
update t_lecture_stdnt
set auth_status=0
where edu_seq=#{eduSeq}
